use strict;
use warnings;

my @students = (
    { name => "Ahmet", grade => 85 },
    { name => "Ayse", grade => 92 },
    { name => "Mehmet", grade => 67 },
    { name => "Zeynep", grade => 78 },
    { name => "Can", grade => 55 },
);

print "Tum ogrenciler:\n";
foreach my $s (@students) {
    print "$s->{name}: $s->{grade}\n";
}

# Yeni ogrenci ekleme
push @students, { name => "Elif", grade => 88 };
print "\nElif eklendi. Toplam ogrenci: " . scalar(@students) . "\n";

# Not güncelleme
foreach my $s (@students) {
    if ($s->{name} eq "Mehmet") {
        $s->{grade} = 70;
        print "\nMehmet'in notu guncellendi: $s->{grade}\n";
    }
}

# Geçenler / kalanlar
my @passing = grep { $_->{grade} >= 60 } @students;
my @failing = grep { $_->{grade} < 60 } @students;

print "\nGecen ogrenci sayisi: " . scalar(@passing) . "\n";
print "Kalan ogrenci sayisi: " . scalar(@failing) . "\n";

# Sıralama (en yüksekten en düşüğe)
my @sorted_students = sort { $b->{grade} <=> $a->{grade} } @students;

print "\nNot siralamasi (yuksekten alcaga):\n";
foreach my $s (@sorted_students) {
    print "$s->{name}: $s->{grade}\n";
}

# Ortalama
my $total = 0;
$total += $_->{grade} for @students;
printf "\nSinif ortalamasi: %.2f\n", $total / scalar(@students);
